class DatabaseQueryBuilder {
  static buildInsertQuery(tableName, data) {
    MessageValidator.validateTableName(tableName);

    const columns = [];
    const values = [];
    const placeholders = [];
    let paramIndex = 1;

    for (const [key, value] of Object.entries(data)) {
      MessageValidator.validateColumnName(tableName, key);
      MessageValidator.validateValue(value);

      columns.push(key);
      values.push(value);
      placeholders.push(`$${paramIndex++}`);
    }

    if (columns.length === 0) {
      throw new Error('No valid columns to insert');
    }

    const query = `INSERT INTO ${tableName} (${columns.join(', ')}) VALUES (${placeholders.join(', ')}) RETURNING *`;
    return { query, values };
  }

  static buildUpdateQuery(tableName, data, whereClause) {
    MessageValidator.validateTableName(tableName);

    const setClauses = [];
    const values = [];
    let paramIndex = 1;

    for (const [key, value] of Object.entries(data)) {
      MessageValidator.validateColumnName(tableName, key);
      MessageValidator.validateValue(value);

      setClauses.push(`${key} = $${paramIndex++}`);
      values.push(value);
    }

    if (setClauses.length === 0) {
      throw new Error('No valid columns to update');
    }

    const whereConditions = [];
    for (const [key, value] of Object.entries(whereClause)) {
      MessageValidator.validateColumnName(tableName, key);
      MessageValidator.validateValue(value);

      whereConditions.push(`${key} = $${paramIndex++}`);
      values.push(value);
    }

    if (whereConditions.length === 0) {
      throw new Error('WHERE clause is required for UPDATE');
    }

    const query = `UPDATE ${tableName} SET ${setClauses.join(', ')} WHERE ${whereConditions.join(' AND ')} RETURNING *`;
    return { query, values };
  }

  static buildDeleteQuery(tableName, whereClause) {
    MessageValidator.validateTableName(tableName);

    const whereConditions = [];
    const values = [];
    let paramIndex = 1;

    for (const [key, value] of Object.entries(whereClause)) {
      MessageValidator.validateColumnName(tableName, key);
      MessageValidator.validateValue(value);

      whereConditions.push(`${key} = $${paramIndex++}`);
      values.push(value);
    }

    if (whereConditions.length === 0) {
      throw new Error('WHERE clause is required for DELETE');
    }

    const query = `DELETE FROM ${tableName} WHERE ${whereConditions.join(' AND ')} RETURNING *`;
    return { query, values };
  }

  static buildSelectQuery(tableName, whereClause = {}, columns = ['*']) {
    MessageValidator.validateTableName(tableName);

    if (columns[0] !== '*') {
      columns.forEach(col => MessageValidator.validateColumnName(tableName, col));
    }

    const values = [];
    let paramIndex = 1;
    const whereConditions = [];

    for (const [key, value] of Object.entries(whereClause)) {
      MessageValidator.validateColumnName(tableName, key);
      MessageValidator.validateValue(value);

      whereConditions.push(`${key} = $${paramIndex++}`);
      values.push(value);
    }

    let query = `SELECT ${columns.join(', ')} FROM ${tableName}`;
    if (whereConditions.length > 0) {
      query += ` WHERE ${whereConditions.join(' AND ')}`;
    }
    query += ' LIMIT 1000';

    return { query, values };
  }
}

