class RabbitMQConsumer {
  constructor(url, queueName, processor) {
    this.url = url;
    this.queueName = queueName;
    this.processor = processor;
    this.connection = null;
    this.channel = null;
  }

  async connect() {
    try {
      this.connection = await amqp.connect(this.url);
      this.channel = await this.connection.createChannel();

      await this.channel.assertQueue(this.queueName, {
        durable: true,
        maxLength: 10000
      });

      await this.channel.prefetch(10);

      console.log(`Connected to RabbitMQ. Waiting for messages in queue: ${this.queueName}`);

      this.connection.on('error', (err) => {
        console.error('RabbitMQ connection error:', err);
      });

      this.connection.on('close', () => {
        console.log('RabbitMQ connection closed. Reconnecting...');
        setTimeout(() => this.connect(), 5000);
      });

    } catch (error) {
      console.error('Failed to connect to RabbitMQ:', error);
      setTimeout(() => this.connect(), 5000);
    }
  }

  async consume() {
    if (!this.channel) {
      throw new Error('Channel not initialized. Call connect() first.');
    }

    this.channel.consume(this.queueName, async (msg) => {
      if (!msg) {
        return;
      }

      try {
        const content = msg.content.toString();

        if (content.length > MAX_MESSAGE_SIZE) {
          throw new Error('Message size exceeds maximum allowed size');
        }

        const message = JSON.parse(content);

        const result = await this.processor.processMessage(message);

        console.log('Message processed successfully:', {
          type: message.type,
          result: result.success
        });

        this.channel.ack(msg);

      } catch (error) {
        console.error('Error processing message:', error.message);

        const redeliveryCount = msg.properties.headers['x-redelivery-count'] || 0;

        if (redeliveryCount < 3) {
          this.channel.nack(msg, false, true);
        } else {
          console.error('Message exceeded max retries, sending to DLQ');
          this.channel.nack(msg, false, false);
        }
      }
    });
  }

  async close() {
    if (this.channel) {
      await this.channel.close();
    }
    if (this.connection) {
      await this.connection.close();
    }
  }
}

async function initializeDatabase() {
  const client = await pool.connect();
  try {
    await client.query(`
      CREATE TABLE IF NOT EXISTS users (
        id SERIAL PRIMARY KEY,
        email VARCHAR(255) UNIQUE NOT NULL,
        name VARCHAR(255) NOT NULL,
        status VARCHAR(50) NOT NULL,
        created_at TIMESTAMP NOT NULL,
        updated_at TIMESTAMP NOT NULL
      )
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS orders (
        id SERIAL PRIMARY KEY,
        user_id INTEGER NOT NULL,
        status VARCHAR(50) NOT NULL,
        total DECIMAL(10, 2) NOT NULL,
        created_at TIMESTAMP NOT NULL,
        updated_at TIMESTAMP NOT NULL
      )
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS inventory (
        id SERIAL PRIMARY KEY,
        product_id INTEGER UNIQUE NOT NULL,
        quantity INTEGER NOT NULL,
        updated_at TIMESTAMP NOT NULL
      )
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS notifications (
        id SERIAL PRIMARY KEY,
        user_id INTEGER NOT NULL,
        message TEXT NOT NULL,
        type VARCHAR(50) NOT NULL,
        sent_at TIMESTAMP NOT NULL
      )
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS audit_logs (
        id SERIAL PRIMARY KEY,
        event_type VARCHAR(100) NOT NULL,
        entity_id INTEGER,
        data JSONB,
        created_at TIMESTAMP NOT NULL
      )
    `);

    console.log('Database tables initialized successfully');
  } finally {
    client.release();
  }
}

async function main() {
  try {
    await initializeDatabase();

    const processor = new MessageProcessor(pool);
    const consumer = new RabbitMQConsumer(RABBITMQ_URL, QUEUE_NAME, processor);

    await consumer.connect();
    await consumer.consume();

    process.on('SIGINT', async () => {
      console.log('Shutting down gracefully...');
      await consumer.close();
      await pool.end();
      process.exit(0);
    });

    process.on('SIGTERM', async () => {
      console.log('Shutting down gracefully...');
      await consumer.close();
      await pool.end();
      process.exit(0);
    });

  } catch (error) {
    console.error('Fatal error:', error);
    process.exit(1);
  }
}

